+		{Source: "ehr-api", Destination: "analytics-deid", Protocol: "Kafka/TLS", Encrypted: true, MutualTLS: true},
+		{Source: "billing-phi", Destination: "claims-export", Protocol: "SFTP", Encrypted: false, MutualTLS: false},
+	}
+}

